//	WHERE cstc.organization_id = ? AND cstc.business_unit_id = ?
//
// Returns the same *bun.SelectQuery so it can be chained fluently:
//
//	buncolgen.CostingControlScopeTenant(sq, ti).
//		Where(buncolgen.CostingControlColumns.ID.Eq(), id)
func CostingControlScopeTenant(q *bun.SelectQuery, ti pagination.TenantInfo) *bun.SelectQuery {
	return ScopeTenant(q, CostingControlColumns.OrganizationID, CostingControlColumns.BusinessUnitID, ti)
}

// CostingControlScopeTenantUpdate restricts an update query to a single tenant.
// Use this inside UpdateQuery.WhereGroup callbacks:
//
//	WhereGroup(" AND ", func(uq *bun.UpdateQuery) *bun.UpdateQuery {
//		return buncolgen.CostingControlScopeTenantUpdate(uq, req.TenantInfo).
//			Where(buncolgen.CostingControlColumns.ID.In(), bun.List(ids))
//	})
func CostingControlScopeTenantUpdate(q *bun.UpdateQuery, ti pagination.TenantInfo) *bun.UpdateQuery {
	return ScopeTenantUpdate(q, CostingControlColumns.OrganizationID, CostingControlColumns.BusinessUnitID, ti)
}

// CostingControlScopeTenantDelete restricts a delete query to a single tenant.
// Use this inside DeleteQuery.WhereGroup callbacks:
//
//	WhereGroup(" AND ", func(dq *bun.DeleteQuery) *bun.DeleteQuery {
//		return buncolgen.CostingControlScopeTenantDelete(dq, req.TenantInfo).
//			Where(buncolgen.CostingControlColumns.ID.Eq(), id)
//	})
func CostingControlScopeTenantDelete(q *bun.DeleteQuery, ti pagination.TenantInfo) *bun.DeleteQuery {
	return ScopeTenantDelete(q, CostingControlColumns.OrganizationID, CostingControlColumns.BusinessUnitID, ti)
}

// CostingControlApplyTenant returns a closure for SelectQuery.Apply() that scopes to a single tenant.
// Use this instead of wrapping ScopeTenant in an anonymous function:
//
//	q.Apply(buncolgen.CostingControlApplyTenant(tenantInfo))
func CostingControlApplyTenant(ti pagination.TenantInfo) func(*bun.SelectQuery) *bun.SelectQuery {
	return ApplyTenant(CostingControlColumns.OrganizationID, CostingControlColumns.BusinessUnitID, ti)
}

